1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface ClaimStep {
23	  op: "claim";
24	  policy: number;
25	  incident: {
26	    cause?: string;
27	    damages: Damage[];
28	  };
29	}
30	
31	export type Step = QuoteStep | ClaimStep;
32	
33	export interface Scenario {
34	  customer: Customer;
35	  steps: Step[];
36	}
37	
38	export interface QuoteResult {
39	  premium: number;
40	}
41	
42	export interface ClaimResult {
43	  payout: number;
44	  remainingCap: number;
45	}
46	
47	export type StepResult = QuoteResult | ClaimResult;
48	
49	export interface ScenarioResult {
50	  results: StepResult[];
51	}
52	
53	const PROCESSING_FEE = 5;
54	
55	const ITEM_BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	  moonstone: 25,
62	};
63	
64	const basePremiumFor = (item: Item): number => {
65	  const premium = ITEM_BASE_PREMIUM[item.type];
66	  if (premium === undefined) throw new Error(`Unknown item type: ${item.type}`);
67	  return premium;
68	};
69	
70	const COMPONENT_BLOCK_PREMIUM = 60;
71	
72	const sumBasePremiums = (items: Item[]): number =>
73	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
74	
75	const COMPONENT_TYPES = ["rune", "moonstone"];
76	
77	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
78	
79	const componentGroupTotal = (group: Item[]): number =>
80	  group.length === 3 ? COMPONENT_BLOCK_PREMIUM : sumBasePremiums(group);
81	
82	const componentsTotal = (items: Item[]): number =>
83	  COMPONENT_TYPES.reduce(
84	    (sum, type) => sum + componentGroupTotal(items.filter((i) => i.type === type)),
85	    0,
86	  );
87	
88	const itemsBaseTotal = (items: Item[]): number =>
89	  sumBasePremiums(items.filter((i) => !isComponent(i))) + componentsTotal(items);
90	
91	const CURSE_SURCHARGE_RATE = 0.5;
92	const HIGH_ENCHANTMENT_THRESHOLD = 5;
93	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
94	
95	const isCursed = (item: Item): boolean => item.cursed === true;
96	const isHighlyEnchanted = (item: Item): boolean =>
97	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
98	
99	const ITEM_SURCHARGE_RATES: ReadonlyArray<(item: Item) => number> = [
100	  (item) => (isCursed(item) ? CURSE_SURCHARGE_RATE : 0),
101	  (item) => (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0),
102	];
103	
104	const itemSurchargeRate = (item: Item): number =>
105	  ITEM_SURCHARGE_RATES.reduce((sum, rate) => sum + rate(item), 0);
106	
107	const itemSurcharges = (items: Item[]): number =>
108	  items.reduce((sum, item) => sum + basePremiumFor(item) * itemSurchargeRate(item), 0);
109	
110	const LOYALTY_THRESHOLD_YEARS = 2;
111	const LOYALTY_DISCOUNT_RATE = 0.2;
112	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
113	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
114	
115	const isLoyal = (customer: Customer): boolean =>
116	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
117	
118	const policyDiscountRate = (customer: Customer): number =>
119	  isLoyal(customer) ? LOYALTY_DISCOUNT_RATE : 0;
120	
121	const followUpDiscountRate = (isFollowUp: boolean): number =>
122	  isFollowUp ? FOLLOW_UP_DISCOUNT_RATE : 0;
123	
124	const policyAdjustedBase = (
125	  baseTotal: number,
126	  customer: Customer,
127	  isFollowUp: boolean,
128	): number =>
129	  baseTotal * (1 - policyDiscountRate(customer) - followUpDiscountRate(isFollowUp)) +
130	  baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
131	
132	const quote = (
133	  { items }: QuoteStep,
134	  customer: Customer,
135	  isFollowUp: boolean,
136	): QuoteResult => ({
137	  premium: Math.ceil(
138	    policyAdjustedBase(itemsBaseTotal(items), customer, isFollowUp) +
139	      itemSurcharges(items) +
140	      PROCESSING_FEE,
141	  ),
142	});
143	
144	const hasPriorQuote = (steps: Step[], index: number): boolean =>
145	  steps.slice(0, index).some((s) => s.op === "quote");
146	
147	const ITEM_INSURANCE_VALUE: Record<string, number> = {
148	  sword: 1000,
149	  amulet: 600,
150	  staff: 800,
151	  potion: 400,
152	  rune: 250,
153	  moonstone: 250,
154	};
155	
156	const insuranceValueFor = (item: Item): number => ITEM_INSURANCE_VALUE[item.type];
157	
158	const insuranceSum = (items: Item[]): number =>
159	  items.reduce((sum, item) => sum + insuranceValueFor(item), 0);
160	
161	const DEDUCTIBLE = 100;
162	const CAP_MULTIPLIER = 2;
163	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
164	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
165	
166	const reimbursementRate = (item: Item): number =>
167	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD
168	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
169	    : 1;
170	
171	const findInsuredItem = (items: Item[], itemType: string): Item =>
172	  items.find((i) => i.type === itemType) as Item;
173	
174	const damagePayout = (damage: Damage, items: Item[]): number => {
175	  if (damage.amount < 0) throw new Error(`Negative damage amount: ${damage.amount}`);
176	  const insured = findInsuredItem(items, damage.itemType);
177	  return damage.amount * reimbursementRate(insured) - DEDUCTIBLE;
178	};
179	
180	const sumDamagePayouts = (damages: Damage[], items: Item[]): number =>
181	  damages.reduce((sum, d) => sum + damagePayout(d, items), 0);
182	
183	const insuranceCap = (items: Item[]): number => insuranceSum(items) * CAP_MULTIPLIER;
184	
185	const policyItems = (steps: Step[], policyIndex: number): Item[] =>
186	  (steps[policyIndex] as QuoteStep).items;
187	
188	const roundDownInFavor = (amount: number): number => Math.floor(amount);
189	
190	const cappedAt = (amount: number, cap: number): number => Math.min(amount, cap);
191	
192	const priorPayoutsOnPolicy = (
193	  steps: Step[],
194	  results: StepResult[],
195	  policy: number,
196	): number =>
197	  results.reduce((sum, result, i) => {
198	    const priorStep = steps[i];
199	    return priorStep.op === "claim" && priorStep.policy === policy
200	      ? sum + (result as ClaimResult).payout
201	      : sum;
202	  }, 0);
203	
204	const countByType = (entries: { type?: string; itemType?: string }[], key: string): number =>
205	  entries.filter((e) => (e.type ?? e.itemType) === key).length;
206	
207	const validateDamageCounts = (damages: Damage[], items: Item[]): void => {
208	  damages.forEach((d) => {
209	    const damageCount = countByType(damages, d.itemType);
210	    const insuredCount = countByType(items, d.itemType);
211	    if (damageCount > insuredCount) {
212	      throw new Error(
213	        `More damage entries (${damageCount}) than insured items (${insuredCount}) of type ${d.itemType}`,
214	      );
215	    }
216	  });
217	};
218	
219	const claim = (step: ClaimStep, steps: Step[], results: StepResult[]): ClaimResult => {
220	  const items = policyItems(steps, step.policy);
221	  validateDamageCounts(step.incident.damages, items);
222	  const cap = insuranceCap(items);
223	  const alreadyPaid = priorPayoutsOnPolicy(steps, results, step.policy);
224	  const remaining = cap - alreadyPaid;
225	  const uncappedPayout = roundDownInFavor(sumDamagePayouts(step.incident.damages, items));
226	  const payout = cappedAt(uncappedPayout, remaining);
227	  return { payout, remainingCap: remaining - payout };
228	};
229	
230	export const runScenario = (scenario: Scenario): ScenarioResult => ({
231	  results: scenario.steps.reduce<StepResult[]>((results, step, index) => {
232	    const result =
233	      step.op === "quote"
234	        ? quote(step, scenario.customer, hasPriorQuote(scenario.steps, index))
235	        : claim(step, scenario.steps, results);
236	    return [...results, result];
237	  }, []),
238	});
